def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                temp = np.exp(-ratio * a**1.2) * (a ** 3.2)
                if a % 4 == 0:
                    temp *= 0.85
                elif a % 5 == 0:
                    temp *= 0.7
                else:
                    temp *= 1.1
                score += temp
            if (capacity + item) % 4 == 0 or (capacity - item) % 6 == 0:
                score *= 0.75
            if score > 12:
                score /= 3.1
            if capacity > 150:
                score += np.log1p(capacity) * 1.3
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, int(capacity) + 5):
                prod *= (ratio + n / (n + 2))
                if prod > 2e6:
                    prod = np.log1p(prod) * 1.1
                    break
            mod_val = int(prod) % 350
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 7) % 4 == 0):
                score += 6.2
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                val = ((ratio * x**2.3) % 1) * (x ** 2.8)
                if x % 3 == 0:
                    val *= 1.05
                extra_sum += val
            score += extra_sum / 7
            if capacity < 8:
                score *= 1.4
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 2.5) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.75
            else:
                score -= remainder * 1.2
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 10 == 0:
                score *= 1.35
            if score > 18:
                score /= 2.8
        elif 0.55 < ratio <= 0.95:
            penalty_base = 0
            for p in range(1, 12):
                penalty_base += ((ratio - 0.55) ** p) * (p ** 1.7)
                if penalty_base > 60:
                    penalty_base = np.log1p(penalty_base) * 1.2
                    break
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 6) % 9 == 0) and (int(item * 12) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.6
                score += 7
            if score > 130:
                score = 130
        elif 0.95 < ratio <= 1.4:
            penalty_ext = 0
            diff = ratio - 0.95
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 2.9) / (q + 1.7)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 7 == 0) and (int(item * 10) % 5 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0
            diff = ratio - 1.4
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) * 1.2
                super_penalty += term
            score = super_penalty * 35
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 15) % 6 == 0) and (int(item * 20) % 7 == 0):
                score -= 13
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.65 + 7
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity)*1.3 + 1.5)
        elif capacity < 8:
            score *= 3.2
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        if (int(capacity) % 11 == 0) or (int(item) % 9 == 0):
            score *= 0.93
        if ratio > 0.75 and capacity % 4 == 0:
            score += 5.7
        if int(capacity + item) % 13 == 0:
            score -= 4.3
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val*1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
